     1→// Package tests provides a comprehensive testing harness for OwlDB implementations.
     2→// It includes utilities for starting/stopping servers, making HTTP requests,
     3→// and validating responses according to the OwlDB specification.
     4→package tests
     5→
     6→import (
     7→	"bufio"
     8→	"bytes"
     9→	"context"
    10→	"encoding/json"
    11→	"fmt"
    12→	"io"
    13→	"net/http"
    14→	"os"
    15→	"os/exec"
    16→	"path/filepath"
    17→	"strings"
    18→	"sync"
    19→	"time"
    20→)
    21→
    22→// TestResult represents the outcome of a single test
    23→type TestResult struct {
    24→	Name     string        `json:"name"`
    25→	Passed   bool          `json:"passed"`
    26→	Duration time.Duration `json:"duration"`
    27→	Error    string        `json:"error,omitempty"`
    28→	Details  string        `json:"details,omitempty"`
    29→}
    30→
    31→// TestSuite represents a collection of related tests
    32→type TestSuite struct {
    33→	Name    string       `json:"name"`
    34→	Results []TestResult `json:"results"`
    35→}
    36→
    37→// TestHarness manages the test server and executes tests
    38→type TestHarness struct {
    39→	ServerBinary string
    40→	SchemaFile   string
    41→	TokenFile    string
    42→	Port         int
    43→	ServerCmd    *exec.Cmd
    44→	BaseURL      string
    45→	Token        string
    46→	mu           sync.Mutex
    47→}
    48→
    49→// WaitForServer is a public wrapper for waitForServer
    50→func (h *TestHarness) WaitForServer(timeout time.Duration) error {
    51→	return h.waitForServer(timeout)
    52→}
    53→
    54→// NewTestHarness creates a new test harness
    55→func NewTestHarness(serverBinary, schemaFile, tokenFile string, port int) *TestHarness {
    56→	return &TestHarness{
    57→		ServerBinary: serverBinary,
    58→		SchemaFile:   schemaFile,
    59→		TokenFile:    tokenFile,
    60→		Port:         port,
    61→		BaseURL:      fmt.Sprintf("http://localhost:%d", port),
    62→	}
    63→}
    64→
    65→// StartServer starts the OwlDB server
    66→func (h *TestHarness) StartServer(ctx context.Context) error {
    67→	h.mu.Lock()
    68→	defer h.mu.Unlock()
    69→
    70→	args := []string{
    71→		"-p", fmt.Sprintf("%d", h.Port),
    72→		"-s", h.SchemaFile,
    73→	}
    74→	if h.TokenFile != "" {
    75→		args = append(args, "-t", h.TokenFile)
    76→	}
    77→
    78→	h.ServerCmd = exec.CommandContext(ctx, h.ServerBinary, args...)
    79→	h.ServerCmd.Stdout = os.Stdout
    80→	h.ServerCmd.Stderr = os.Stderr
    81→
    82→	if err := h.ServerCmd.Start(); err != nil {
    83→		return fmt.Errorf("failed to start server: %w", err)
    84→	}
    85→
    86→	// Wait for server to be ready
    87→	return h.waitForServer(10 * time.Second)
    88→}
    89→
    90→// waitForServer waits for the server to accept connections
    91→func (h *TestHarness) waitForServer(timeout time.Duration) error {
    92→	deadline := time.Now().Add(timeout)
    93→	for time.Now().Before(deadline) {
    94→		resp, err := http.Get(h.BaseURL + "/v1/")
    95→		if err == nil {
    96→			resp.Body.Close()
    97→			return nil
    98→		}
    99→		time.Sleep(100 * time.Millisecond)
   100→	}
   101→	return fmt.Errorf("server did not start within %v", timeout)
   102→}
   103→
   104→// StopServer stops the OwlDB server
   105→func (h *TestHarness) StopServer() error {
   106→	h.mu.Lock()
   107→	defer h.mu.Unlock()
   108→
   109→	if h.ServerCmd != nil && h.ServerCmd.Process != nil {
   110→		if err := h.ServerCmd.Process.Signal(os.Interrupt); err != nil {
   111→			return h.ServerCmd.Process.Kill()
   112→		}
   113→		h.ServerCmd.Wait()
   114→	}
   115→	return nil
   116→}
   117→
   118→// SetToken sets the bearer token for authenticated requests
   119→func (h *TestHarness) SetToken(token string) {
   120→	h.Token = token
   121→}
   122→
   123→// HTTPRequest makes an HTTP request and returns the response
   124→func (h *TestHarness) HTTPRequest(method, path string, body interface{}) (*HTTPResponse, error) {
   125→	var bodyReader io.Reader
   126→	if body != nil {
   127→		jsonBody, err := json.Marshal(body)
   128→		if err != nil {
   129→			return nil, fmt.Errorf("failed to marshal body: %w", err)
   130→		}
   131→		bodyReader = bytes.NewReader(jsonBody)
   132→	}
   133→
   134→	url := h.BaseURL + path
   135→	req, err := http.NewRequest(method, url, bodyReader)
   136→	if err != nil {
   137→		return nil, fmt.Errorf("failed to create request: %w", err)
   138→	}
   139→
   140→	if body != nil {
   141→		req.Header.Set("Content-Type", "application/json")
   142→	}
   143→	if h.Token != "" {
   144→		req.Header.Set("Authorization", "Bearer "+h.Token)
   145→	}
   146→
   147→	client := &http.Client{Timeout: 30 * time.Second}
   148→	resp, err := client.Do(req)
   149→	if err != nil {
   150→		return nil, fmt.Errorf("request failed: %w", err)
   151→	}
   152→	defer resp.Body.Close()
   153→
   154→	respBody, err := io.ReadAll(resp.Body)
   155→	if err != nil {
   156→		return nil, fmt.Errorf("failed to read response: %w", err)
   157→	}
   158→
   159→	return &HTTPResponse{
   160→		StatusCode:  resp.StatusCode,
   161→		Headers:     resp.Header,
   162→		Body:        respBody,
   163→		ContentType: resp.Header.Get("Content-Type"),
   164→	}, nil
   165→}
   166→
   167→// HTTPResponse represents an HTTP response
   168→type HTTPResponse struct {
   169→	StatusCode  int
   170→	Headers     http.Header
   171→	Body        []byte
   172→	ContentType string
   173→}
   174→
   175→// JSON parses the response body as JSON
   176→func (r *HTTPResponse) JSON() (map[string]interface{}, error) {
   177→	var result map[string]interface{}
   178→	if err := json.Unmarshal(r.Body, &result); err != nil {
   179→		return nil, err
   180→	}
   181→	return result, nil
   182→}
   183→
   184→// JSONArray parses the response body as a JSON array
   185→func (r *HTTPResponse) JSONArray() ([]interface{}, error) {
   186→	var result []interface{}
   187→	if err := json.Unmarshal(r.Body, &result); err != nil {
   188→		return nil, err
   189→	}
   190→	return result, nil
   191→}
