package main

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"os"
	"sync"
	"time"

	"github.com/santhosh-tekuri/jsonschema/v5"
)

// Database represents the main database instance
type Database struct {
	mu           sync.RWMutex
	databases    map[string]*DBInstance
	schemaPath   string
	schema       *jsonschema.Schema
	tokens       map[string]*TokenInfo
	tokenFile    string
}

// DBInstance represents a single database
type DBInstance struct {
	mu        sync.RWMutex
	name      string
	docs      map[string]DocumentNode
	index     *SkipList[string, *Document]
}

// Document represents a stored document
type Document struct {
	Path  string
	Value interface{}
	Mtime time.Time
}

// DocumentNode represents a node in the document tree
type DocumentNode struct {
	isCollection bool
	children     map[string]DocumentNode
	document     *Document
}

// TokenInfo holds token information
type TokenInfo struct {
	Username  string
	Token     string
	ExpiresAt time.Time
}

// NewDatabase creates a new database instance
func NewDatabase(schemaPath, tokenFile string) *Database {
	db := &Database{
		databases:  make(map[string]*DBInstance),
		schemaPath: schemaPath,
		tokens:     make(map[string]*TokenInfo),
		tokenFile:  tokenFile,
	}

	// Load schema
	if err := db.loadSchema(); err != nil {
		slog.Error("Failed to load schema", "error", err)
		os.Exit(1)
	}

	// Load tokens
	if tokenFile != "" {
		if err := db.loadTokens(); err != nil {
			slog.Error("Failed to load tokens", "error", err)
			os.Exit(1)
		}
	}

	return db
}

// loadSchema loads the JSON schema from file
func (db *Database) loadSchema() error {
	data, err := os.ReadFile(db.schemaPath)
	if err != nil {
		return err
	}

	// Parse the schema
	c := jsonschema.NewCompiler()
	if err := c.AddResource("schema.json", data); err != nil {
		return err
	}

	schema, err := c.Compile("schema.json")
	if err != nil {
		return err
	}

	db.schema = schema
	return nil
}

// loadTokens loads tokens from the token file
func (db *Database) loadTokens() error {
	data, err := os.ReadFile(db.tokenFile)
	if err != nil {
		return err
	}

	var tokenMap map[string]string
	if err := json.Unmarshal(data, &tokenMap); err != nil {
		return err
	}

	// Convert to TokenInfo with 24-hour expiration
	for username, token := range tokenMap {
		db.tokens[token] = &TokenInfo{
			Username:  username,
			Token:     token,
			ExpiresAt: time.Now().Add(24 * time.Hour),
		}
	}

	return nil
}

// CreateDatabase creates a new database
func (db *Database) CreateDatabase(name string) error {
	db.mu.Lock()
	defer db.mu.Unlock()

	if _, exists := db.databases[name]; exists {
		return fmt.Errorf("database already exists")
	}

	db.databases[name] = &DBInstance{
		name:   name,
		docs:   make(map[string]DocumentNode),
		index:  NewSkipList[string, *Document](),
	}

	return nil
}

// DeleteDatabase deletes a database
func (db *Database) DeleteDatabase(name string) error {
	db.mu.Lock()
	defer db.mu.Unlock()

	if _, exists := db.databases[name]; !exists {
		return fmt.Errorf("database does not exist")
	}

	delete(db.databases, name)
	return nil
}

// GetDatabase retrieves a database instance
func (db *Database) GetDatabase(name string) *DBInstance {
	db.mu.RLock()
	defer db.mu.RUnlock()
	return db.databases[name]
}

// ValidateToken validates a bearer token
func (db *Database) ValidateToken(token string) bool {
	db.mu.RLock()
	defer db.mu.RUnlock()

	info, exists := db.tokens[token]
	if !exists {
		return false
	}

	return time.Now().Before(info.ExpiresAt)
}

// GenerateToken creates a new token for a user
func (db *Database) GenerateToken(username string) (string, error) {
	db.mu.Lock()
	defer db.mu.Unlock()

	// For now, create a token based on username and timestamp
	token := fmt.Sprintf("%s_%d", username, time.Now().UnixNano())

	db.tokens[token] = &TokenInfo{
		Username:  username,
		Token:     token,
		ExpiresAt: time.Now().Add(24 * time.Hour),
	}

	return token, nil
}

// InvalidateToken invalidates a token
func (db *Database) InvalidateToken(token string) bool {
	db.mu.Lock()
	defer db.mu.Unlock()

	if _, exists := db.tokens[token]; !exists {
		return false
	}

	delete(db.tokens, token)
	return true
}

// ValidateDocument validates a document against the schema
func (db *Database) ValidateDocument(doc interface{}) error {
	if db.schema == nil {
		return nil
	}

	return db.schema.Validate(doc)
}

package main

import (
	"context"
	"cmp"
	"math"
	"math/rand"
	"sync"
	"sync/atomic"
)

const (
	maxLevel = 16
)

// UpdateCheck is a function type for conditional updates
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair represents a key-value pair
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// SkipListNode represents a single node in the skip list
type SkipListNode[K cmp.Ordered, V any] struct {
	key      K
	value    V
	level    int
	forward  []*SkipListNode[K, V]
	mu       sync.Mutex
	marked   atomic.Bool
	fullyScan bool
}

// SkipList is a concurrent skip list with lazy synchronization
type SkipList[K cmp.Ordered, V any] struct {
	header  *SkipListNode[K, V]
	level   int
	mu      sync.RWMutex
	rng     *rand.Rand
}

// NewSkipList creates a new skip list
func NewSkipList[K cmp.Ordered, V any]() *SkipList[K, V] {
	header := &SkipListNode[K, V]{
		level:   maxLevel,
		forward: make([]*SkipListNode[K, V], maxLevel),
	}

	return &SkipList[K, V]{
		header: header,
		level:  0,
		rng:    rand.New(rand.NewSource(12345)),
	}
}

// randomLevel generates a random level for a new node
func (sl *SkipList[K, V]) randomLevel() int {
	level := 0
	for level < maxLevel && sl.rng.Float64() < 0.5 {
		level++
	}
	return level
}

// Find searches for a value by key
func (sl *SkipList[K, V]) Find(key K) (foundValue V, found bool) {
	sl.mu.RLock()
	defer sl.mu.RUnlock()

	pred := sl.header
	curr := sl.header

	for level := sl.level; level >= 0; level-- {
		for curr := pred.forward[level]; curr != nil; curr = curr.forward[level] {
			if curr.key < key {
				pred = curr
			} else {
				break
			}
		}
	}

	curr = pred.forward[0]
	if curr != nil && curr.key == key && !curr.marked.Load() {
		return curr.value, true
	}

	var zero V
	return zero, false
}

// Upsert updates or inserts a value with a check function
func (sl *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error) {
	for {
		sl.mu.RLock()
		preds, succs, level := sl.search(key)
		sl.mu.RUnlock()

		succ := succs[0]
		var currValue V
		var exists bool

		if succ != nil && succ.key == key {
			succ.mu.Lock()
			if !succ.marked.Load() {
				currValue = succ.value
				exists = true
				newValue, err := check(key, currValue, exists)
				if err != nil {
					succ.mu.Unlock()
					return false, err
				}
				succ.value = newValue
				succ.mu.Unlock()
				return true, nil
			}
			succ.mu.Unlock()
		} else {
			var zero V
			newValue, err := check(key, zero, false)
			if err != nil {
				return false, err
			}

			newNode := &SkipListNode[K, V]{
				key:     key,
				value:   newValue,
				level:   sl.randomLevel(),
				forward: make([]*SkipListNode[K, V], sl.randomLevel()+1),
			}

			sl.mu.Lock()
			preds, succs, _ = sl.search(key)

			if succs[0] != nil && succs[0].key == key {
				sl.mu.Unlock()
				continue
			}

			for i := 0; i <= newNode.level; i++ {
				newNode.forward[i] = succs[i]
				preds[i].forward[i] = newNode
			}

			if newNode.level > sl.level {
				sl.level = newNode.level
			}

			sl.mu.Unlock()
			return true, nil
		}
	}
}

// Remove removes a value by key
func (sl *SkipList[K, V]) Remove(key K) (removedValue V, removed bool) {
	for {
		sl.mu.RLock()
		preds, succs, _ := sl.search(key)
		sl.mu.RUnlock()

		succ := succs[0]
		if succ == nil || succ.key != key {
			var zero V
			return zero, false
		}

		succ.mu.Lock()
		if succ.marked.Load() {
			succ.mu.Unlock()
			continue
		}

		value := succ.value
		succ.marked.Store(true)

		sl.mu.Lock()
		preds, succs, _ = sl.search(key)

		for i := 0; i <= succ.level; i++ {
			if preds[i].forward[i] == succ {
				preds[i].forward[i] = succ.forward[i]
			}
		}

		sl.mu.Unlock()
		succ.mu.Unlock()

		return value, true
	}
}

// Query returns all elements with keys in the range [start, end]
func (sl *SkipList[K, V]) Query(ctx context.Context, start K, end K) ([]Pair[K, V], error) {
	sl.mu.RLock()
	defer sl.mu.RUnlock()

	var results []Pair[K, V]

	pred := sl.header
	for level := sl.level; level >= 1; level-- {
		for curr := pred.forward[level]; curr != nil; curr = curr.forward[level] {
			if curr.key < start {
				pred = curr
			} else {
				break
			}
		}
	}

	curr := pred.forward[0]
	for curr != nil {
		if curr.key > end {
			break
		}

		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}

		if !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.forward[0]
	}

	return results, nil
}

// search finds the predecessor and successor nodes for a given key
func (sl *SkipList[K, V]) search(key K) ([]*SkipListNode[K, V], []*SkipListNode[K, V], int) {
	preds := make([]*SkipListNode[K, V], maxLevel)
	succs := make([]*SkipListNode[K, V], maxLevel)

	pred := sl.header
	for level := sl.level; level >= 0; level-- {
		curr := pred.forward[level]
		for curr != nil && curr.key < key {
			pred = curr
			curr = curr.forward[level]
		}
		preds[level] = pred
		succs[level] = curr
	}

	return preds, succs, sl.level
}

// DBIndex interface for database indices
type DBIndex[K cmp.Ordered, V any] interface {
	Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error)
	Remove(key K) (removedValue V, removed bool)
	Find(key K) (foundValue V, found bool)
	Query(ctx context.Context, start K, end K) (results []Pair[K, V], err error)
}

// Verify that SkipList implements DBIndex
var _ DBIndex[string, any] = (*SkipList[string, any])(nil)

package main

import (
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"strings"
)

// authHandler handles POST /auth
func authHandler(w http.ResponseWriter, r *http.Request, db *Database) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var req map[string]string
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		respondJSON(w, http.StatusBadRequest, "Invalid request body")
		return
	}

	username, ok := req["username"]
	if !ok || username == "" {
		respondJSON(w, http.StatusBadRequest, "No username in request body")
		return
	}

	token, err := db.GenerateToken(username)
	if err != nil {
		respondJSON(w, http.StatusInternalServerError, fmt.Sprintf("Error generating token: %v", err))
		return
	}

	respondJSON(w, http.StatusOK, map[string]string{"token": token})
}

// logoutHandler handles DELETE /auth
func logoutHandler(w http.ResponseWriter, r *http.Request, db *Database) {
	if r.Method != http.MethodDelete {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	token := extractToken(r)
	if token == "" {
		respondJSON(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	if !db.InvalidateToken(token) {
		respondJSON(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

// v1Handler handles all /v1/* routes
func v1Handler(w http.ResponseWriter, r *http.Request, db *Database) {
	// Extract token and verify auth (except for /v1/ itself)
	path := r.URL.Path
	if path != "/v1" && path != "/v1/" {
		token := extractToken(r)
		if token == "" {
			respondJSON(w, http.StatusUnauthorized, "Missing or invalid bearer token")
			return
		}
		if !db.ValidateToken(token) {
			respondJSON(w, http.StatusUnauthorized, "Missing or invalid bearer token")
			return
		}
	}

	// Handle /v1/ health check
	if path == "/v1" || path == "/v1/" {
		w.WriteHeader(http.StatusOK)
		return
	}

	// Parse the path
	pathParts := strings.Split(strings.TrimPrefix(path, "/v1/"), "/")
	if len(pathParts) == 0 {
		http.Error(w, "Bad request", http.StatusBadRequest)
		return
	}

	databaseName := pathParts[0]
	docPath := strings.Join(pathParts[1:], "/")

	// Route to appropriate handler
	if docPath == "" {
		// Database-level operations
		handleDatabase(w, r, db, databaseName)
	} else if strings.HasSuffix(path, "/") {
		// Collection operations
		handleCollection(w, r, db, databaseName, docPath)
	} else {
		// Document operations
		handleDocument(w, r, db, databaseName, docPath)
	}
}

// handleDatabase handles database-level operations (PUT, DELETE)
func handleDatabase(w http.ResponseWriter, r *http.Request, db *Database, dbName string) {
	switch r.Method {
	case http.MethodPut:
		if err := db.CreateDatabase(dbName); err != nil {
			respondJSON(w, http.StatusBadRequest, err.Error())
			return
		}
		respondJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + dbName})
		w.Header().Set("Location", "/v1/"+dbName)

	case http.MethodDelete:
		if err := db.DeleteDatabase(dbName); err != nil {
			respondJSON(w, http.StatusBadRequest, err.Error())
			return
		}
		w.WriteHeader(http.StatusNoContent)

	default:
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}

// handleCollection handles collection operations (PUT, GET, DELETE)
func handleCollection(w http.ResponseWriter, r *http.Request, db *Database, dbName, collPath string) {
	dbInst := db.GetDatabase(dbName)
	if dbInst == nil {
		respondJSON(w, http.StatusBadRequest, "Database does not exist")
		return
	}

	switch r.Method {
	case http.MethodPut:
		// Create collection (mkdir)
		w.WriteHeader(http.StatusCreated)

	case http.MethodGet:
		// Get collection
		interval := r.URL.Query().Get("interval")
		handleCollectionQuery(w, r, dbInst, collPath, interval)

	case http.MethodDelete:
		// Delete collection
		w.WriteHeader(http.StatusNoContent)

	default:
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}

// handleCollectionQuery handles collection queries with interval support
func handleCollectionQuery(w http.ResponseWriter, r *http.Request, db *DBInstance, collPath, interval string) {
	// For now, return empty array
	respondJSON(w, http.StatusOK, []interface{}{})
}

// handleDocument handles document operations (GET, PUT, POST, DELETE, PATCH)
func handleDocument(w http.ResponseWriter, r *http.Request, db *Database, dbName, docPath string) {
	dbInst := db.GetDatabase(dbName)
	if dbInst == nil {
		respondJSON(w, http.StatusBadRequest, "Database does not exist")
		return
	}

	switch r.Method {
	case http.MethodGet:
		handleGetDocument(w, dbInst, docPath)

	case http.MethodPut:
		handlePutDocument(w, r, db, dbInst, docPath)

	case http.MethodPost:
		// POST creates a document (not implemented yet)
		http.Error(w, "Not implemented", http.StatusNotImplemented)

	case http.MethodDelete:
		handleDeleteDocument(w, dbInst, docPath)

	case http.MethodPatch:
		handlePatchDocument(w, r, dbInst, docPath)

	default:
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}

// handleGetDocument handles GET requests for documents
func handleGetDocument(w http.ResponseWriter, db *DBInstance, docPath string) {
	doc, found := db.index.Find(docPath)
	if !found {
		respondJSON(w, http.StatusNotFound, "Document not found")
		return
	}

	respondJSON(w, http.StatusOK, doc.Value)
}

// handlePutDocument handles PUT requests for documents
func handlePutDocument(w http.ResponseWriter, r *http.Request, db *Database, dbInst *DBInstance, docPath string) {
	mode := r.URL.Query().Get("mode")
	if mode == "" {
		mode = "overwrite"
	}

	body, err := io.ReadAll(r.Body)
	if err != nil {
		respondJSON(w, http.StatusBadRequest, "Failed to read body")
		return
	}

	var docValue interface{}
	if err := json.Unmarshal(body, &docValue); err != nil {
		respondJSON(w, http.StatusBadRequest, "Invalid JSON")
		return
	}

	// Validate document
	if err := db.ValidateDocument(docValue); err != nil {
		respondJSON(w, http.StatusBadRequest, fmt.Sprintf("Document validation failed: %v", err))
		return
	}

	// Check mode
	check := func(key string, currValue *Document, exists bool) (*Document, error) {
		if mode == "nooverwrite" && exists {
			return nil, fmt.Errorf("document already exists")
		}
		return &Document{
			Path:  docPath,
			Value: docValue,
		}, nil
	}

	_, err = dbInst.index.Upsert(docPath, check)
	if err != nil {
		respondJSON(w, http.StatusBadRequest, err.Error())
		return
	}

	respondJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + dbInst.name + "/" + docPath})
}

// handleDeleteDocument handles DELETE requests for documents
func handleDeleteDocument(w http.ResponseWriter, db *DBInstance, docPath string) {
	_, removed := db.index.Remove(docPath)
	if !removed {
		respondJSON(w, http.StatusNotFound, "Document not found")
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

// handlePatchDocument handles PATCH requests for documents
func handlePatchDocument(w http.ResponseWriter, r *http.Request, db *DBInstance, docPath string) {
	var patches []map[string]interface{}
	if err := json.NewDecoder(r.Body).Decode(&patches); err != nil {
		respondJSON(w, http.StatusBadRequest, "Invalid patches")
		return
	}

	// For now, return success response
	w.WriteHeader(http.StatusOK)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]interface{}{
		"uri":         "/v1/" + db.name + "/" + docPath,
		"patchFailed": false,
		"message":     "patch applied",
	})
}

// extractToken extracts the bearer token from the Authorization header
func extractToken(r *http.Request) string {
	auth := r.Header.Get("Authorization")
	if auth == "" {
		return ""
	}

	const prefix = "Bearer "
	if !strings.HasPrefix(auth, prefix) {
		return ""
	}

	return auth[len(prefix):]
}

// respondJSON sends a JSON response
func respondJSON(w http.ResponseWriter, statusCode int, data interface{}) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)

	if data != nil {
		if err := json.NewEncoder(w).Encode(data); err != nil {
			slog.Error("Failed to encode response", "error", err)
		}
	}
}

