package main

import (
	"fmt"
	"strings"

	"owldb/jsondata"
)

// PatchOperation represents a single PATCH operation
type PatchOperation struct {
	Op    string      `json:"op"`
	Path  string      `json:"path"`
	Value interface{} `json:"value"`
}

// ApplyPatches applies a list of patch operations to a document
func ApplyPatches(doc interface{}, patches []map[string]interface{}) (interface{}, bool, string) {
	// Convert document to JSONValue
	docValue, err := jsondata.NewJSONValue(doc)
	if err != nil {
		return doc, true, fmt.Sprintf("Failed to convert document: %v", err)
	}

	// Apply each patch in order
	for _, p := range patches {
		op, ok := p["op"].(string)
		if !ok {
			return doc, true, "Missing or invalid op field"
		}

		path, ok := p["path"].(string)
		if !ok {
			return doc, true, "Missing or invalid path field"
		}

		value, ok := p["value"]
		if !ok {
			return doc, true, "Missing value field"
		}

		// Apply the patch operation
		var newValue interface{}
		switch op {
		case "ArrayAdd":
			var updated bool
			newValue, updated, err = applyArrayAdd(docValue, path, value)
			if err != nil || !updated {
				return doc, true, fmt.Sprintf("ArrayAdd failed: %v", err)
			}

		case "ArrayRemove":
			var updated bool
			newValue, updated, err = applyArrayRemove(docValue, path, value)
			if err != nil || !updated {
				return doc, true, fmt.Sprintf("ArrayRemove failed: %v", err)
			}

		case "ObjectAdd":
			var updated bool
			newValue, updated, err = applyObjectAdd(docValue, path, value)
			if err != nil || !updated {
				return doc, true, fmt.Sprintf("ObjectAdd failed: %v", err)
			}

		default:
			return doc, true, fmt.Sprintf("Unknown operation: %s", op)
		}

		docValue, _ = jsondata.NewJSONValue(newValue)
	}

	// Return the modified document
	finalDoc, _ := unwrapJSONValue(docValue)
	return finalDoc, false, "patch applied"
}

// applyArrayAdd adds a value to an array
func applyArrayAdd(doc jsondata.JSONValue, path string, value interface{}) (interface{}, bool, error) {
	// Parse the path and navigate to the target
	target, modified, err := navigateAndModify(doc, path, func(target interface{}) (interface{}, bool, error) {
		arr, ok := target.([]interface{})
		if !ok {
			return target, false, fmt.Errorf("path does not refer to an array")
		}

		// Check if value already exists
		for _, item := range arr {
			if deepEqual(item, value) {
				return target, false, nil // Already exists, no change
			}
		}

		// Add the value
		newArr := append(arr, value)
		return newArr, true, nil
	})

	if err != nil {
		return nil, false, err
	}

	return target, modified, nil
}

// applyArrayRemove removes a value from an array
func applyArrayRemove(doc jsondata.JSONValue, path string, value interface{}) (interface{}, bool, error) {
	target, modified, err := navigateAndModify(doc, path, func(target interface{}) (interface{}, bool, error) {
		arr, ok := target.([]interface{})
		if !ok {
			return target, false, fmt.Errorf("path does not refer to an array")
		}

		// Find and remove the value
		newArr := make([]interface{}, 0)
		found := false
		for _, item := range arr {
			if !deepEqual(item, value) {
				newArr = append(newArr, item)
			} else {
				found = true
			}
		}

		if !found {
			return target, false, nil // Value not found, no change
		}

		return newArr, true, nil
	})

	if err != nil {
		return nil, false, err
	}

	return target, modified, nil
}

// applyObjectAdd adds a property to an object
func applyObjectAdd(doc jsondata.JSONValue, path string, value interface{}) (interface{}, bool, error) {
	target, modified, err := navigateAndModify(doc, path, func(target interface{}) (interface{}, bool, error) {
		obj, ok := target.(map[string]interface{})
		if !ok {
			return target, false, fmt.Errorf("path does not refer to an object property")
		}

		// Split the path to get the last key
		parts := strings.Split(strings.Trim(path, "/"), "/")
		if len(parts) == 0 {
			return target, false, fmt.Errorf("invalid path")
		}

		key := parts[len(parts)-1]

		// Check if property already exists
		if _, exists := obj[key]; exists {
			return target, false, nil // Property already exists
		}

		// Add the property
		obj[key] = value
		return obj, true, nil
	})

	if err != nil {
		return nil, false, err
	}

	return target, modified, nil
}

// navigateAndModify navigates to a path and applies a modification function
func navigateAndModify(doc jsondata.JSONValue, path string, modifyFunc func(interface{}) (interface{}, bool, error)) (interface{}, bool, error) {
	// For now, implement a simple version that works for single-level paths
	parts := strings.Split(strings.Trim(path, "/"), "/")

	// Unwrap the document
	docData, _ := unwrapJSONValue(doc)

	if len(parts) == 0 || parts[0] == "" {
		// Root modification
		return modifyFunc(docData)
	}

	// Navigate to the parent of the target
	current := docData
	for i := 0; i < len(parts)-1; i++ {
		if m, ok := current.(map[string]interface{}); ok {
			current = m[parts[i]]
		} else {
			return docData, false, fmt.Errorf("path does not exist")
		}
	}

	// Apply modification to the parent
	if m, ok := current.(map[string]interface{}); ok {
		key := parts[len(parts)-1]
		target := m[key]

		modified, isModified, err := modifyFunc(target)
		if err != nil {
			return docData, false, err
		}

		if isModified {
			m[key] = modified
		}

		return docData, isModified, nil
	}

	return docData, false, fmt.Errorf("path does not refer to an object")
}

// deepEqual checks if two values are deeply equal
func deepEqual(a, b interface{}) bool {
	// Simple implementation - can be enhanced
	switch av := a.(type) {
	case map[string]interface{}:
		bv, ok := b.(map[string]interface{})
		if !ok {
			return false
		}
		if len(av) != len(bv) {
			return false
		}
		for k, v := range av {
			if !deepEqual(v, bv[k]) {
				return false
			}
		}
		return true

	case []interface{}:
		bv, ok := b.([]interface{})
		if !ok {
			return false
		}
		if len(av) != len(bv) {
			return false
		}
		for i := range av {
			if !deepEqual(av[i], bv[i]) {
				return false
			}
		}
		return true

	case string, float64, bool, nil:
		return a == b

	default:
		return a == b
	}
}

// unwrapJSONValue unwraps a JSONValue to its underlying Go value
func unwrapJSONValue(jv jsondata.JSONValue) (interface{}, error) {
	// Use a simple visitor to get the underlying value
	visitor := &unwrapVisitor{}
	return jsondata.Accept(jv, visitor)
}

// unwrapVisitor is a visitor that unwraps a JSONValue
type unwrapVisitor struct{}

func (v *unwrapVisitor) Map(m map[string]jsondata.JSONValue) (interface{}, error) {
	result := make(map[string]interface{})
	for k, jv := range m {
		val, _ := unwrapJSONValue(jv)
		result[k] = val
	}
	return result, nil
}

func (v *unwrapVisitor) Slice(s []jsondata.JSONValue) (interface{}, error) {
	result := make([]interface{}, len(s))
	for i, jv := range s {
		val, _ := unwrapJSONValue(jv)
		result[i] = val
	}
	return result, nil
}

func (v *unwrapVisitor) Bool(b bool) (interface{}, error) {
	return b, nil
}

func (v *unwrapVisitor) Float64(f float64) (interface{}, error) {
	return f, nil
}

func (v *unwrapVisitor) String(s string) (interface{}, error) {
	return s, nil
}

func (v *unwrapVisitor) Null() (interface{}, error) {
	return nil, nil
}

