// handleCollectionQuery handles collection queries with interval support
func handleCollectionQuery(w http.ResponseWriter, r *http.Request, db *DBInstance, collPath, interval string) {
	ctx := r.Context()

	// Parse interval if provided
	var start, end string
	start = ""
	end = ""

	if interval != "" {
		// Parse interval format: [low,high]
		interval = strings.TrimPrefix(interval, "[")
		interval = strings.TrimSuffix(interval, "]")
		parts := strings.Split(interval, ",")
		if len(parts) >= 1 {
			start = parts[0]
		}
		if len(parts) >= 2 {
			end = parts[1]
		}
	}

	// If no bounds specified, use empty strings to match all
	if start == "" && end == "" {
		start = "\x00"          // Minimum string
		end = "\uffff\uffff"    // Maximum string
	} else if start == "" {
		start = "\x00"
	} else if end == "" {
		end = "\uffff\uffff"
	}

	// Prefix search for collection documents
	collPrefix := collPath
	if collPrefix != "" && !strings.HasSuffix(collPrefix, "/") {
		collPrefix += "/"
	}

	// Query the index for documents in this collection
	results, err := db.index.Query(ctx, start, end)
	if err != nil {
		respondJSON(w, http.StatusInternalServerError, fmt.Sprintf("Query failed: %v", err))
		return
	}

	// Filter results to only include documents in the collection
	var docs []interface{}
	for _, pair := range results {
		docPath := pair.Key
		// Check if document is in the collection
		if collPrefix == "" || strings.HasPrefix(docPath, collPrefix) {
			docs = append(docs, pair.Value.Value)
		}
	}

	if docs == nil {
		docs = []interface{}{}
	}

	respondJSON(w, http.StatusOK, docs)
}

