// handleSubscribeDocument handles document subscription
func handleSubscribeDocument(w http.ResponseWriter, db *DBInstance, docPath string, sm *SubscriptionManager) {
	// Get the current document
	doc, found := db.index.Find(docPath)

	// Create subscription
	sub := sm.Subscribe(docPath, "", false, "", "")

	// Set up SSE headers
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")

	// Send initial event if document exists
	if found {
		sendSSEEvent(w, "update", docPath, doc.Value)
		w.(http.Flusher).Flush()
	} else {
		sendSSEEvent(w, "initial", docPath, nil)
		w.(http.Flusher).Flush()
	}

	// Listen for changes
	ticker := time.NewTicker(30 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case event := <-sub.Events:
			sendSSEEvent(w, event.Type, event.Path, event.Value)
			w.(http.Flusher).Flush()

		case <-ticker.C:
			// Keep-alive ping
			fmt.Fprintf(w, ": keepalive\n\n")
			w.(http.Flusher).Flush()

		case <-r.Context().Done():
			sm.Unsubscribe(sub.ID)
			return

		case <-sub.Done:
			return
		}
	}
}

